// File: HeadsetReceiver.kt — receives system broadcast
import android.content.*

class HeadsetReceiver : BroadcastReceiver() {
  override fun onReceive(context: Context, intent: Intent) {
    if (intent.action == Intent.ACTION_HEADSET_PLUG) {
      val plugged = intent.getIntExtra("state", 0) == 1
      android.util.Log.d("HS", if (plugged) "headphones plugged in" else "unplugged")
    }
  }
}

// Register/unregister dynamically in an Activity — tied to Activity lifecycle
class MainActivity : AppCompatActivity() {
  private val receiver = HeadsetReceiver()

  override fun onStart() {
    super.onStart()
    val filter = IntentFilter(Intent.ACTION_HEADSET_PLUG)
    registerReceiver(receiver, filter)
  }

  override fun onStop() {
    super.onStop()
    unregisterReceiver(receiver)   // MUST unregister or leak
  }

  // Fire a custom broadcast to notify other components (or apps)
  private fun notifySyncDone() {
    // Since Android 14 (API 34), you must specify RECEIVER_EXPORTED or RECEIVER_NOT_EXPORTED
    val intent = Intent("com.myapp.SYNC_DONE")
      .setPackage(packageName)   // limit to our own app for privacy
      .putExtra("count", 42)
    sendBroadcast(intent)
  }
}

